// Helper function to simulate the kernel logic for a single block
void dynproc_block(int iteration,
                   int* gpuWall,
                   int* gpuSrc,
                   int* gpuResults,
                   int cols,
                   int rows,
                   int startStep,
                   int border,
                   int HALO,
                   int BLOCK_SIZE,
                   int bx,
                   int* outputBuffer)
{
    // Simulate local memory using vectors
    int* prev = new int[BLOCK_SIZE];
    int* result = new int[BLOCK_SIZE];

    int tx_start = bx * BLOCK_SIZE;

    int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
    int blkX = (small_block_cols*bx) - border;
    int blkXmax = blkX+BLOCK_SIZE-1;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

    // Initialize prev and handle boundaries
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        int xidx = blkX + tx;
        if (IN_RANGE(xidx, 0, cols-1)) {
            prev[tx] = gpuSrc[xidx];
        } else {
            prev[tx] = 0; // Or some safe default, though logic relies on validX
        }
    }

    bool computed = false;

    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        // Parallel loop over tx within the block
        #pragma omp parallel for
        for (int tx = 0; tx < BLOCK_SIZE; tx++)
        {
            int xidx = blkX + tx;
            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid)
            {
                int W = tx-1;
                int E = tx+1;
                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;

                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                result[tx] = shortest + gpuWall[index];

                computed = true;

                if (tx==11 && i==0)
                {
                    int bufIndex = gpuSrc[xidx];
                    if (bufIndex >= 0 && bufIndex < 16384) {
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }
        }

        if(i==iteration-1)
        {
            break;
        }

        if(computed)
        {
            #pragma omp parallel for
            for(int tx = 0; tx < BLOCK_SIZE; tx++) {
                if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax)) {
                    prev[tx] = result[tx];
                }
            }
        }
    }

    // Write back results
    #pragma omp parallel for
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
    {
        int xidx = blkX + tx;
        bool isValid = IN_RANGE(tx, validXmin, validXmax);
        // The original code checks 'computed' which is a scalar from the loop. 
        // In the original, 'computed' is set if ANY thread computed. 
        // However, the write back depends on the specific thread's computation status.
        // Re-evaluating condition per thread to be safe and correct in parallel
        if (IN_RANGE(xidx, 0, cols-1) && IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax)) {
             // Actually, the original code sets 'computed' inside the loop and uses it after.
             // But 'computed' is a local bool. In OpenCL, each thread has its own flow.
             // The original code: if (computed) gpuResults[xidx] = result[tx];
             // This implies only threads that performed computation write back.
             // We must replicate the condition.
             // The condition for computation was: IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid
             // Since we are at the end of the loop (i = iteration-1 effectively for the last write),
             // we check if this thread computed in the last iteration.
             // Actually, the variable 'computed' in the original kernel is local to the thread?
             // No, in OpenCL C, variables declared inside the function without __local/__global are automatic (local to thread).
             // So 'bool computed' is per-thread.
             // My previous translation used a shared 'computed'. Let's fix that.
             // Wait, looking at the source:
             // bool computed;
             // for ... { computed = false; if (...) { computed = true; ... } }
             // if (computed) { gpuResults[xidx] = result[tx]; }
             // Yes, 'computed' is per-thread state.

             // Re-implementing the per-thread logic properly inside the parallel region or just re-checking condition.
             // Since we are outside the loop now, we just check if the thread would have computed in the last step.
             // The last step is i = iteration - 1.
             // Condition: IN_RANGE(tx, (iteration-1)+1, BLOCK_SIZE-(iteration-1)-2) => IN_RANGE(tx, iteration, BLOCK_SIZE-iteration-1)
             // And isValid.

             int last_i = iteration - 1;
             bool was_valid = IN_RANGE(tx, validXmin, validXmax);
             bool was_in_range = IN_RANGE(tx, last_i+1, BLOCK_SIZE-last_i-2);

             if (was_in_range && was_valid) {
                 gpuResults[xidx] = result[tx];
             }
        }
    }

    delete[] prev;
    delete[] result;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

    // Determine block size. 
    // In OpenCL, this is queried from the kernel. 
    // We need a heuristic or fixed value that matches the expected behavior.
    // The original code uses clGetKernelWorkGroupInfo. 
    // Common values are 256, 128, 64. 
    // Let's assume 256 as a default safe block size for this translation, 
    // or derive it from environment. 
    // To ensure correctness without the binary, we pick a standard size.
    // The original logic: lwsize = min(max_work_group_size, gwsize) adjusted for divisibility.
    // We'll use 256.
    int BLOCK_SIZE = 256;
    if (cols < BLOCK_SIZE) BLOCK_SIZE = cols;
    // Ensure divisibility if possible, or just use what fits.
    while (cols % BLOCK_SIZE != 0 && BLOCK_SIZE > 1) {
        BLOCK_SIZE--;
    }

    int num_blocks = (cols + BLOCK_SIZE - 1) / BLOCK_SIZE;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulate buffers
    // gpuWall corresponds to data + cols (size - cols)
    int* d_gpuWall = data + cols; 
    // d_gpuResult[0] and [1] correspond to data and result buffers
    int* d_gpuResult_0 = data;
    int* d_gpuResult_1 = result;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // No explicit H2D copy needed as we are using host memory directly

	int src = 1, final_ret = 0;

    double kernel_start_time = 0.0;
    double kernel_end_time = 0.0;

#ifdef TIMING
    kernel_start_time = omp_get_wtime();
#endif

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows-t-1);
		int theHalo = HALO;

        int* current_src = (src == 0) ? d_gpuResult_0 : d_gpuResult_1;
        int* current_dest = (final_ret == 0) ? d_gpuResult_0 : d_gpuResult_1;

        // Parallelize over blocks
        #pragma omp parallel for
        for (int bx = 0; bx < num_blocks; bx++) {
            dynproc_block(arg0,
                          d_gpuWall,
                          current_src,
                          current_dest,
                          cols,
                          rows,
                          t,
                          borderCols,
                          theHalo,
                          BLOCK_SIZE,
                          bx,
                          h_outputBuffer);
        }
	}

#ifdef TIMING
    kernel_end_time = omp_get_wtime();
    kernel_time = (kernel_end_time - kernel_start_time) * 1000.0;
#endif

    // Results are already in 'result' (d_gpuResult[final_ret]) due to direct mapping

    // Read outputBuffer (already in host memory)

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

    free(h_outputBuffer);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif


	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}
